com.mirth.connect.plugins.javascriptstep.script:
logger.info(msg['Parameters']);
if (msg['Parameters']['hosnum'].toString()) {
    tmp['QPD']['QPD.3']['QPD.3.1'] = msg['Parameters']['hosnum'].toString();
} else if (msg['Parameters']['nhsnum'].toString()) {
    tmp['QPD']['QPD.3']['QPD.3.1'] = msg['Parameters']['nhsnum'].toString();
    tmp['QPD']['QPD.3']['QPD.3.4'] = "NHS";
    tmp['QPD']['QPD.3']['QPD.3.5'] = "NHS";
}
else {
    tmp['QPD']['QPD.3']['QPD.3.1'] = "";
}

properties.script:
var destination = responseMap.get('Send Q21');
var responseMessage = destination.getMessage().replace('""','');
var Xmsg = new XML(SerializerFactory.getSerializer('HL7V2').toXML(responseMessage));

//var xml_msg = '<?xml version="1.0" encoding="utf-8" ?>'+
//              '<XML><Patient Name="'+Xmsg['PID']['PID.5']['PID.5.1']+
//              '" Barcode="'+Xmsg['QRD']['QRD.8']['QRD.8.1']+'" /></XML>';

var sResp = ResponseFactory.getSentResponse(Xmsg)

responseMap.put('K21ResponseXML', sResp);

channel.postprocessingScript:
// This script executes once after a message has been processed
// Responses returned from here will be stored as "Postprocessor" in the response map
return;

channel.deployScript:
// This script executes once when the channel is deployed
// You only have access to the globalMap and globalChannelMap here to persist data
return;

channel.undeployScript:
// This script executes once when the channel is undeployed
// You only have access to the globalMap and globalChannelMap here to persist data
return;
